text.regex:
(?isx)
^
# Current formal claimant / destination must be the shipper-side party.
(?=
  .*?
  (?:
    (?:merchant(?:\s+shipper)?|shipper|account[\s_-]*holder|seller|sender)
    [^.!?\n]{0,180}
    (?:should|must|needs?\s+to|has\s+to|is\s+responsible\s+for|is\s+the\s+(?:correct|proper|appropriate|right)\s+(?:party|actor)\s+to|can)
    [^.!?\n]{0,100}
    (?:file|initiat(?:e|ed|ing)?|open|submit|start|handle)
    [^.!?\n]{0,80}
    (?:the\s+)?(?:formal\s+)?(?:damage(?:d)?\s+shipment\s+)?claim
  |
    (?:the\s+)?(?:formal\s+)?(?:damage(?:d)?\s+shipment\s+)?claim
    [^.!?\n]{0,180}
    (?:should|must|needs?\s+to|has\s+to)
    [^.!?\n]{0,80}
    (?:be\s+)?
    (?:filed|initiated|opened|submitted|started|handled)
    [^.!?\n]{0,100}
    (?:by\s+)?(?:the\s+)?
    (?:merchant(?:\s+shipper)?|shipper|account[\s_-]*holder|seller|sender)
  |
    (?:contact|ask|have|request)
    [^.!?\n]{0,100}
    (?:merchant(?:\s+shipper)?|shipper|account[\s_-]*holder|seller|sender)
    [^.!?\n]{0,120}
    (?:file|initiat(?:e|ed|ing)?|open|submit|start|handle)
    [^.!?\n]{0,80}
    (?:the\s+)?(?:formal\s+)?(?:damage(?:d)?\s+shipment\s+)?claim
  |
    (?:route|direct|send)
    [^.!?\n]{0,80}
    (?:the\s+)?(?:formal\s+)?(?:damage(?:d)?\s+shipment\s+)?claim
    [^.!?\n]{0,80}
    (?:through|to)
    [^.!?\n]{0,50}
    (?:the\s+)?(?:merchant(?:\s+shipper)?|shipper|account[\s_-]*holder|seller|sender)
  )
)
# The receiver's current filing path must be bounded by authorization.
(?=
  .*?
  (?:
    (?:receiver|recipient|you|customer)
    [^.!?\n]{0,100}
    (?:
      (?:cannot|can't|may\s+not|should\s+not|must\s+not|is\s+not\s+authorized|isn't\s+authorized|are\s+not\s+authorized|aren't\s+authorized|is\s+unable|isn't\s+able|are\s+unable|aren't\s+able)
      [^.!?\n]{0,100}
      (?:file|initiat(?:e|ed|ing)?|open|submit|start)
      [^.!?\n]{0,80}
      (?:the\s+)?(?:formal\s+)?claim
    |
      (?:needs?|requires?|must\s+(?:obtain|get)|has\s+to\s+(?:obtain|get))
      [^.!?\n]{0,100}
      (?:a\s+)?(?:letter\s+of\s+)?authorization
      [^.!?\n]{0,100}
      (?:before|to|in\s+order\s+to)
      [^.!?\n]{0,80}
      (?:file|initiat(?:e|ed|ing)?|open|submit|start)
      [^.!?\n]{0,80}
      (?:the\s+)?(?:formal\s+)?claim
    |
      (?:may|can)
      [^.!?\n]{0,50}
      (?:file|initiat(?:e|ed|ing)?|open|submit|start)
      [^.!?\n]{0,80}
      (?:the\s+)?(?:formal\s+)?claim
      [^.!?\n]{0,80}
      (?:only\s+with|after|once)
      [^.!?\n]{0,60}
      (?:a\s+)?(?:letter\s+of\s+)?authorization
    )
  |
    (?:merchant(?:\s+shipper)?|shipper|account[\s_-]*holder|seller|sender)
    [^.!?\n]{0,120}
    (?:must|needs?\s+to|has\s+to|should)
    [^.!?\n]{0,100}
    authoriz(?:e|es|ed|ation)
    [^.!?\n]{0,100}
    (?:receiver|recipient|you|customer)
    [^.!?\n]{0,100}
    (?:before|to\s+allow|so\s+that)
    [^.!?\n]{0,80}
    (?:file|initiat(?:e|ed|ing)?|open|submit|start)
  )
)
# Reject narrow, explicit contradictions about immediate unapproved filing.
(?!
  .*?
  (?:
    (?:receiver|recipient|you|customer)
    [^.!?\n]{0,80}
    (?:can|may|should)
    [^.!?\n]{0,50}
    (?:directly\s+)?
    (?:file|initiat(?:e|ed|ing)?|open|submit|start)
    [^.!?\n]{0,60}
    (?:the\s+)?(?:formal\s+)?claim
    [^.!?\n]{0,40}
    (?:now|immediately|without\s+(?:a\s+)?(?:letter\s+of\s+)?authorization)
  |
    no\s+(?:letter\s+of\s+)?authorization
    [^.!?\n]{0,30}
    (?:is\s+)?(?:needed|required)
  |
    authorization
    [^.!?\n]{0,20}
    (?:is\s+)?(?:not|isn't)\s+(?:needed|required)
  )
)
.*
$
